import java.io.*;
import java.util.*;

public class Main {
    private static String removeKdigits(String num, int k) {
        Deque<Character> dq = new ArrayDeque<>();
        for (char c : num.toCharArray()) {
            while (k > 0 && !dq.isEmpty() && dq.peekLast() > c) {
                dq.pollLast();
                k--;
            }
            dq.addLast(c);
        }
        while (k > 0 && !dq.isEmpty()) {
            dq.pollLast();
            k--;
        }
        while (!dq.isEmpty() && dq.peekFirst() == '0') {
            dq.pollFirst();
        }
        if (dq.isEmpty()) return "0";
        StringBuilder sb = new StringBuilder(dq.size());
        for (char c : dq) sb.append(c);
        return sb.toString();
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder raw = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            raw.append(line).append('\n');
        }
        // Replace escaped newlines ("\\n") with spaces to normalize input
        String processed = raw.toString().replace("\\n", " ");
        Scanner sc = new Scanner(processed);
        StringBuilder out = new StringBuilder();
        if (!sc.hasNextInt()) return; // no test cases
        int T = sc.nextInt();
        for (int t = 0; t < T; t++) {
            int n = sc.nextInt(); // size of num, not used directly
            int k = sc.nextInt();
            String num = sc.next();
            out.append(removeKdigits(num, k));
            if (t + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

